class Solution {
    public String answerString(String word, int numFriends) {
        String max = "";
        for (int i = 0; i < word.length() - numFriends + 1; i++) {
            String sub = word.substring(i, i + numFriends);
            if (sub.compareTo(max) > 0) {
                max = sub;
            }
        }
        return max;
    }
}
